import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionFixed {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String command = reader.readLine();

            // Create a list to store the command and its arguments
            String[] cmdArray = { "/bin/sh", "-c", command };

            // Use ProcessBuilder to execute the command safely
            ProcessBuilder processBuilder = new ProcessBuilder(cmdArray);

            // Redirect error stream to input stream
            processBuilder.redirectErrorStream(true);

            // Start the process
            Process process = processBuilder.start();

